<script setup lang="ts">
import { ref, computed, onMounted } from 'vue'
import type { CSSProperties } from 'vue'

const emit = defineEmits(['change-id'])

const tooltipVisible = ref(false)
const tooltipTitle = ref('')
const tooltipOrderCount = ref(0)

const activeRegion = defineModel()

const tooltipStyle = ref<CSSProperties>({
  position: 'absolute',
  display: 'none',
  backgroundColor: '#fff',
  border: '1px solid black',
  padding: '5px',
  borderRadius: '3px',
  fontFamily: 'Arial, sans-serif',
  fontSize: '14px',
  zIndex: 10,
  pointerEvents: 'none',
  left: '0px',
  top: '0px',
})


const regionList = computed(() => useConstants().regionList)


function openState(id: number, watch = false) {
  const region = regionList.value.find((region) => Number(region.code) === id)
  const paths = (document.querySelector('.uzbekistanmapIcon') as SVGSVGElement)?.querySelectorAll(
    'path'
  )
  paths.forEach((path) => {
    if (Number(path.id) === id) {
      path.classList.add('active')
      if (!watch) {
        activeRegion.value = String(region?.code)
        emit('change-id')
      }
    } else path.classList.remove('active')
  })
}

function removeState () {
  const paths = (document.querySelector('.uzbekistanmapIcon') as SVGSVGElement)?.querySelectorAll(
    'path'
  )
  paths.forEach((path) => {
    path.classList.remove('active')
  })
  emit('change-id')
}

function showTooltip(event: MouseEvent) {
  const target = event.target as SVGPathElement
  const id = target.id
  // const region = regionList.value.find((region) => region.cadastr_id === id)
  // const orderCount =
  //   props.staticsData?.scope_names?.find((scope) => scope.id === region?.id)?.order_count || 0
  tooltipTitle.value = target.getAttribute('title') || ''
  tooltipOrderCount.value = 2
  tooltipStyle.value.display = 'block'
  tooltipVisible.value = true
}

function hideTooltip() {
  tooltipStyle.value.display = 'none'
  tooltipVisible.value = false
}

function moveTooltip(event: MouseEvent) {
  const container = document.querySelector('.respublic-map-container') as HTMLElement
  if (container) {
    const rect = container.getBoundingClientRect()
    tooltipStyle.value.left = `${event.clientX - rect.left + 15}px`
    tooltipStyle.value.top = `${event.clientY - rect.top + 15}px`
  }
}

onMounted(() => {
  const paths = (document.querySelector('.uzbekistanmapIcon') as SVGSVGElement)?.querySelectorAll(
    'path'
  )
  paths?.forEach((path) => {
    path.addEventListener('mouseenter', showTooltip)
    path.addEventListener('mouseleave', hideTooltip)
    path.addEventListener('mousemove', moveTooltip)
  })
})

defineExpose({
  removeState
})
</script>
<style scoped>
.respublic-map-container {
  position: relative;
}

svg {
  display: block;
}

.tooltip {
  display: none;
  position: absolute;
  background-color: #fff;
  border: 1px solid #ccc;
  padding: 5px;
  border-radius: 3px;
  box-shadow: 0px 0px 5px rgba(0, 0, 0, 0.3);
  font-size: 12px;
  white-space: nowrap;
}
.uzbekistanmapIcon > path {
  cursor: pointer !important;
}
.uzbekistanmapIcon {
  cursor: pointer !important;
}
.uzbekistanmapIcon > path:hover {
  /* fill: var(--color-brown); */
  cursor: pointer !important;
  fill: #004494;
}

.active {
  /* fill: var(--color-brown); */
  fill: var(--color-blue-600);
}
@keyframes slideInRight {
  0% {
    opacity: 0.5;
    transform: translateX(25px);
  }

  100% {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes slideInLeft {
  0% {
    opacity: 0.5;
    transform: translateX(-25px);
  }

  100% {
    opacity: 1;
    transform: translateX(0);
  }
}

.uzbekistanmapIcon {
  width: 100%;
  height: 100%;
}

@keyframes slideOpacity {
  0% {
    opacity: 0.2;
  }

  100% {
    opacity: 1;
  }
}

@keyframes fadeInOut {
  0% {
    opacity: 0.2;
  }

  100% {
    opacity: 1;
  }
}

.animate-right {
  animation: slideInRight 0.8s ease-in-out forwards;
}

.animate-opacity {
  animation: slideOpacity 0.8s ease-in-out forwards;
  animation: fadeInOut 0.8s ease-in-out forwards;
}

.animate-left {
  animation: slideInLeft 0.8s ease-in-out forwards;
}
</style>
